#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 2500
#define MAX_M 2500
#define MAX_T 10000

// Define the structure for a node in the graph
typedef struct Node {
    int x, y;
    int dist;
} Node;

// Define the structure for a queue
typedef struct Queue {
    Node* nodes;
    int front, rear, size;
} Queue;

// Function to create a new queue
Queue* createQueue(int size) {
    Queue* q = (Queue*) malloc(sizeof(Queue));
    q->nodes = (Node*) malloc(size * sizeof(Node));
    q->front = q->rear = -1;
    q->size = size;
    return q;
}

// Function to check if the queue is empty
int isEmpty(Queue* q) {
    return q->front == -1;
}

// Function to check if the queue is full
int isFull(Queue* q) {
    return (q->rear + 1) % q->size == q->front;
}

// Function to enqueue a node
void enqueue(Queue* q, Node node) {
    if (isFull(q)) {
        printf("Queue is full\n");
        return;
    }
    if (isEmpty(q)) {
        q->front = q->rear = 0;
    } else {
        q->rear = (q->rear + 1) % q->size;
    }
    q->nodes[q->rear] = node;
}

// Function to dequeue a node
Node dequeue(Queue* q) {
    if (isEmpty(q)) {
        printf("Queue is empty\n");
        Node node;
        node.x = node.y = node.dist = -1;
        return node;
    }
    Node node = q->nodes[q->front];
    if (q->front == q->rear) {
        q->front = q->rear = -1;
    } else {
        q->front = (q->front + 1) % q->size;
    }
    return node;
}

// Function to perform BFS
void bfs(char room[][MAX_M], int n, int m, int x1, int y1, int x2, int y2) {
    // Create a queue
    Queue* q = createQueue(n * m);
    // Create a visited array
    int visited[n][m];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            visited[i][j] = 0;
        }
    }
    // Enqueue the starting node
    Node start;
    start.x = x1;
    start.y = y1;
    start.dist = 0;
    enqueue(q, start);
    visited[x1][y1] = 1;
    // Perform BFS
    while (!isEmpty(q)) {
        Node node = dequeue(q);
        if (node.x == x2 && node.y == y2) {
            printf("%.2f\n", (float)node.dist / 2);
            return;
        }
        // Explore neighbors
        int dx[] = {-1, 1, 0, 0};
        int dy[] = {0, 0, -1, 1};
        for (int i = 0; i < 4; i++) {
            int nx = node.x + dx[i];
            int ny = node.y + dy[i];
            if (nx >= 0 && nx < n && ny >= 0 && ny < m && room[nx][ny] != '#' && !visited[nx][ny]) {
                Node neighbor;
                neighbor.x = nx;
                neighbor.y = ny;
                neighbor.dist = node.dist + 1;
                enqueue(q, neighbor);
                visited[nx][ny] = 1;
            }
        }
    }
    printf("-1.00\n");
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        char room[n][MAX_M];
        for (int i = 0; i < n; i++) {
            scanf("%s", room[i]);
        }
        int m = strlen(room[0]);
        int x1, y1, x2, y2;
        scanf("%d %d %d %d", &x1, &y1, &x2, &y2);
        bfs(room, n, m, x1, y1, x2, y2);
    }
    return 0;
}

