    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            int n = sc.nextInt();
            char[][] room = new char[n][];
            for (int i = 0; i < n; i++) {
                room[i] = sc.next().toCharArray();
            }
            int m = room[0].length;
            int x1 = sc.nextInt();
            int y1 = sc.nextInt();
            int x2 = sc.nextInt();
            int y2 = sc.nextInt();
            bfs(room, n, m, x1, y1, x2, y2);
        }
    }

    public static void bfs(char[][] room, int n, int m, int x1, int y1, int x2, int y2) {
        // Create a queue
        Queue<int[]> q = new LinkedList<>();
        // Create a visited array
        boolean[][] visited = new boolean[n][m];
        // Enqueue the starting node
        q.add(new int[] {x1, y1, 0});
        visited[x1][y1] = true;
        // Perform BFS
        while (!q.isEmpty()) {
            int[] node = q.poll();
            if (node[0] == x2 && node[1] == y2) {
                System.out.println((float)node[2] / 2);
                return;
            }
            // Explore neighbors
            int dx[] = {-1, 1, 0, 0};
            int dy[] = {0, 0, -1, 1};
            for (int i = 0; i < 4; i++) {
                int nx = node[0] + dx[i];
                int ny = node[1] + dy[i];
                if (nx >= 0 && nx < n && ny >= 0 && ny < m && room[nx][ny] != '#' && !visited[nx][ny]) {
                    q.add(new int[] {nx, ny, node[2] + 1});
                    visited[nx][ny] = true;
                }
            }
        }
        System.out.println(-1.00);
    }
}

